  describe('revokeKey', () => {
    it('builds a valid StorageProgram', () => {
      const program = encryptionHandler.revokeKey({ keyId: {"type":"ref","fixture":"generate_aes","field":"keyId"} });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = encryptionHandler.revokeKey({ keyId: {"type":"ref","fixture":"generate_aes","field":"keyId"} });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('declares completion variants', () => {
      const program = encryptionHandler.revokeKey({ keyId: {"type":"ref","fixture":"generate_aes","field":"keyId"} });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = program.effects?.completionVariants ?? extractCompletionVariants(program);
      expect(variants.size).toBeGreaterThan(0);
    });

    it('declares read and write sets', () => {
      const program = encryptionHandler.revokeKey({ keyId: {"type":"ref","fixture":"generate_aes","field":"keyId"} });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = encryptionHandler.revokeKey({ keyId: {"type":"ref","fixture":"generate_aes","field":"keyId"} });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('produces a result', async () => {
      if (typeof encryptionHandler.revokeKey !== 'function') return;
      const result = await interpret(encryptionHandler.revokeKey({ keyId: {"type":"ref","fixture":"generate_aes","field":"keyId"} }), storage);
      expect(result).toBeDefined();
      if (result.variant !== undefined) {
        expect(typeof result.variant).toBe('string');
      }
    });

    it('fixture "revoke_existing" -> ok', async () => {
      if (typeof encryptionHandler.revokeKey !== 'function') return;
      const storage = createInMemoryStorage();
      const afterResult_list_no_keys = await interpret(encryptionHandler.listKeys({ user: "nobody" }), storage);
      const afterResult_generate_aes = await interpret(encryptionHandler.generateKeyPair({ user: "alice", algorithm: "aes-256-gcm" }), storage);
      const result = await interpret(encryptionHandler.revokeKey({ keyId: afterResult_generate_aes?.output?.["keyId"] }), storage);
      expect(result.variant).toBe('ok');
    });

    it('fixture "revoke_missing" -> notfound', async () => {
      if (typeof encryptionHandler.revokeKey !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await interpret(encryptionHandler.revokeKey({ keyId: "nonexistent-key" }), storage);
      const normalize = (v: string) => v?.toLowerCase().replace(/_/g, '');
      expect(normalize(result.variant)).toBe(normalize('notfound'));
    });

  });

  describe('register()', () => {
    it('declares concept name', async () => {
      if (typeof encryptionHandler.register !== 'function') return;
      const storage = createInMemoryStorage();
      const program = encryptionHandler.register({});
      // If it's a StorageProgram, interpret it
      const result = (program?.instructions && !program.variant)
        ? await interpret(program, storage)
        : program;
      if (!result?.variant) return; // handler does not support register introspection
      expect(result.variant).toBe('ok');
      const name = result.output?.name ?? result.name;
      expect(name).toBe('Encryption');
    });
  });

